#include <stdio.h>
#include <math.h>
int main() {
    int T, N, M, Ci, Pi;
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d", &N, &M);
        int costs[N];
        int colors[N];
        for (int i = 0; i < N; i++) {
            scanf("%d %d", &Ci, &Pi);
            costs[i] = Pi;
            colors[i] = Ci;
        }
        double expectedCost = 0.0;
        for (int mask = 0; mask < (1 << N); mask++) {
            int numColors = 0;
            int subsetCost = 0;
            int colorSet[41] = {0};
            for (int i = 0; i < N; i++) {
                if ((mask & (1 << i)) != 0) {
                    subsetCost += costs[i];
                    colorSet[colors[i]] = 1;
                }
            }
            for (int i = 1; i <= 40; i++) {
                if (colorSet[i] == 1) numColors++;
            }
            if (numColors >= M) {
                expectedCost += subsetCost / pow(2, N);
            }
        }
        printf("%.6f\n", expectedCost);
    }
    return 0;
}

