import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int M = sc.nextInt();
            int[] costs = new int[N];
            int[] colors = new int[N];
            for (int i = 0; i < N; i++) {
                colors[i] = sc.nextInt();
                costs[i] = sc.nextInt();
            }
            double expectedCost = 0.0;
            for (int mask = 0; mask < (1 << N); mask++) {
                int numColors = 0;
                int subsetCost = 0;
                boolean[] colorSet = new boolean[41];
                for (int i = 0; i < N; i++) {
                    if ((mask & (1 << i)) != 0) {
                        subsetCost += costs[i];
                        colorSet[colors[i]] = true;
                    }
                }
                for (int i = 1; i <= 40; i++) {
                    if (colorSet[i]) numColors++;
                }
                if (numColors >= M) {
                    expectedCost += subsetCost / Math.pow(2, N);
                }
            }
            System.out.printf("%.6f\n", expectedCost);
        }
    }
}

code.JavaScript:
const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => lines[idx++];
const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const [N, M] = readline().split(' ').map(Number);
    const costs = [];
    const colors = [];
    for (let j = 0; j < N; j++) {
        const [Ci, Pi] = readline().split(' ').map(Number);
        costs.push(Pi);
        colors.push(Ci);
    }
    let expectedCost = 0.0;
    for (let mask = 0; mask < (1 << N); mask++) {
        let numColors = 0;
        let subsetCost = 0;
        const colorSet = new Set();
        for (let k = 0; k < N; k++) {
            if ((mask & (1 << k)) !== 0) {
                subsetCost += costs[k];
                colorSet.add(colors[k]);
            }
        }
        numColors = colorSet.size;
        if (numColors >= M) {
            expectedCost += subsetCost / Math.pow(2, N);
        }
    }
    console.log(expectedCost.toFixed(6));
}

